UPDATE ctgb_products SET gebruiksvoorschriften = '[{"gewas": "Pootaardappel", "doelorganisme": "Aardappelziekte, Tomatenziekte", "locatie": "Onbedekt", "toepassingsmethode": "Gewasbehandeling", "dosering": "0.5 L/ha", "maxToepassingen": 6, "veiligheidstermijn": "1 dagen", "interval": "min. 5 dagen", "opmerkingen": ["De gegevens van dit gebruik zijn gebaseerd op het wettelijk gebruiksvoorschrift dat geldig is vanaf 01-01-2019. Raadpleeg voor de complete informatie altijd het wettelijk gebruiksvoorschrift en het etiket.\n\nMaximaal aantal toepassingen:\n6 (bij voorkeur 2 blokken van 3 toepassingen). \n\nMaximum dosis per toepassing:\nVerlaging van de dosering is toegestaan, maar van het maximaal aantal toepassingen en de andere toepassingsvoorwaarden mag niet worden afgeweken. Werkzaamheid is vastgesteld voor de genoemde dosering per toepassing en niet voor verlaagde doseringen."], "bbchVan": "15", "bbchTot": "69", "spuitvolumeMin": 200, "spuitvolumeMax": 400, "intervalDagen": 5, "phiDagen": 1}, {"gewas": "Consumptieaardappel, Zetmeelaardappel", "doelorganisme": "Aardappelziekte, Tomatenziekte", "locatie": "Onbedekt", "toepassingsmethode": "Gewasbehandeling", "dosering": "0.5 L/ha", "maxToepassingen": 6, "veiligheidstermijn": "1 dagen", "interval": "min. 5 dagen", "opmerkingen": ["De gegevens van dit gebruik zijn gebaseerd op het wettelijk gebruiksvoorschrift dat geldig is vanaf 01-01-2019. Raadpleeg voor de complete informatie altijd het wettelijk gebruiksvoorschrift en het etiket.\n\nMaximaal aantal toepassingen:\n6 (bij voorkeur 2 blokken van 3 toepassingen). \n\nMaximum dosis per toepassing:\nVerlaging van de dosering is toegestaan, maar van het maximaal aantal toepassingen en de andere toepassingsvoorwaarden mag niet worden afgeweken. Werkzaamheid is vastgesteld voor de genoemde dosering per toepassing en niet voor verlaagde doseringen."], "bbchVan": "15", "bbchTot": "91", "spuitvolumeMin": 200, "spuitvolumeMax": 400, "intervalDagen": 5, "phiDagen": 1}, {"gewas":